### Migrate Payload Admin View Tab `pillLabel` to `Pill` Component

Source: https://github.com/payloadcms/payload/blob/main/docs/migration-guide/overview.mdx

Payload CMS has replaced the `admin.components.views[key].Tab.pillLabel` string property with `admin.components.views[key].tab.Pill`. This change requires replacing the direct label with a path to a custom React component for the pill display.

```diff
// collections/Posts.ts
import type { CollectionConfig } from 'payload'

export const PostsCollection: CollectionConfig = {
  slug: 'posts',
  admin: {
    components: {
-     views: {
-       Edit: {
-         Tab: {
-           pillLabel: 'Hello, world!',
-         },
-       },
+       edit: {
+         tab: {
+           Pill: './path/to/CustomPill.tsx',
+         }
+       },
      },
    },
  }
}
```

